'use strict';

/**
* Reverse a double-precision floating-point strided array in-place according to a mask.
*
* @module @stdlib/blas-ext-base-dmskrev
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import Uint8Array from '@stdlib/array-uint8';
* import dmskrev from '@stdlib/blas-ext-base-dmskrev';
*
* var x = new Float64Array( [ -2.0, 1.0, 3.0, -5.0, 4.0, 0.0, -1.0, -3.0 ] );
* var mask = new Uint8Array( [ 0, 0, 0, 1, 0, 0, 0, 0 ] );
*
* dmskrev( x.length, x, 1, mask, 1 );
* // x => <Float64Array>[ -3.0, -1.0, 0.0, -5.0, 4.0, 3.0, 1.0, -2.0 ]
*
* @example
* import Float64Array from '@stdlib/array-float64';
* import Uint8Array from '@stdlib/array-uint8';
* import dmskrev from '@stdlib/blas-ext-base-dmskrev';
*
* var x = new Float64Array( [ -2.0, 1.0, 3.0, -5.0, 4.0, 0.0, -1.0, -3.0 ] );
* var mask = new Uint8Array( [ 0, 0, 0, 1, 0, 0, 0, 0 ] );
*
* dmskrev.ndarray( x.length, x, 1, 0, mask, 1, 0 );
* // x => <Float64Array>[ -3.0, -1.0, 0.0, -5.0, 4.0, 3.0, 1.0, -2.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var dmskrev;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	dmskrev = main;
} else {
	dmskrev = tmp;
}


// EXPORTS //

export default dmskrev;

