'use strict';

// MODULES //

import stride2offset from '@stdlib/strided-base-stride2offset';
import ndarray from './ndarray.js';


// MAIN //

/**
* Fills a single-precision floating-point strided array with linearly spaced numeric elements which increment by `1` starting from one.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {Float32Array} x - input array
* @param {integer} strideX - stride length
* @returns {Float32Array} input array
*
* @example
* import Float32Array from '@stdlib/array-float32';
*
* var x = new Float32Array( [ 0.0, 0.0, 0.0, 0.0 ] );
*
* soneTo( x.length, x, 1 );
* // x => <Float32Array>[ 1.0, 2.0, 3.0, 4.0 ]
*/
function soneTo( N, x, strideX ) {
	return ndarray( N, x, strideX, stride2offset( N, strideX ) );
}


// EXPORTS //

export default soneTo;
