'use strict';

/**
* Generate a single-precision floating-point Vandermonde matrix.
*
* @module @stdlib/blas-ext-base-svander
*
* @example
* import Float32Array from '@stdlib/array-float32';
* import svander from '@stdlib/blas-ext-base-svander';
*
* var x = new Float32Array( [ 1.0, 2.0, 3.0 ] );
* var out = new Float32Array( 9 );
*
* svander( 'row-major', -1, 3, 3, x, 1, out, 3 );
* // out => <Float32Array>[ 1.0, 1.0, 1.0, 4.0, 2.0, 1.0, 9.0, 3.0, 1.0 ]
*
* @example
* import Float32Array from '@stdlib/array-float32';
* import svander from '@stdlib/blas-ext-base-svander';
*
* var x = new Float32Array( [ 1.0, 2.0, 3.0 ] );
* var out = new Float32Array( 9 );
*
* svander.ndarray( -1, 3, 3, x, 1, 0, out, 3, 1, 0 );
* // out => <Float32Array>[ 1.0, 1.0, 1.0, 4.0, 2.0, 1.0, 9.0, 3.0, 1.0 ]
*/

// MODULES //

var join = require( 'path' ).join;
import tryRequire from '@stdlib/utils-try-require';
import isError from '@stdlib/assert-is-error';
import main from './main.js';


// MAIN //

var svander;
var tmp = tryRequire( join( __dirname, './native.js' ) );
if ( isError( tmp ) ) {
	svander = main;
} else {
	svander = tmp;
}


// EXPORTS //

export default svander;

